#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new();
my $redirect_url = $cgi->param('next') || '/default/page';

# Ensure the redirect URL is safe and internal
if ($redirect_url !~ m{^/}) {
    $redirect_url = '/default/page';  # Fallback to a default page
}

print "Location: $redirect_url\n\n";